# pseudonymizer.py -- consistent fake values within a session
import hashlib
from faker import Faker

fake = Faker()

class SessionPseudonymizer:
    """Replaces real names with consistent fake names within a session."""

    def __init__(self, session_id: str):
        self._session_id = session_id
        self._vault: dict[str, str] = {}  # original -> pseudonym

    def _generate_pseudonym(self, entity_type: str, original: str) -> str:
        # Seed faker deterministically so the same original always gets
        # the same pseudonym within and across sessions with the same seed.
        seed = int(hashlib.sha256(
            f"{self._session_id}:{entity_type}:{original}".encode()
        ).hexdigest(), 16) % (2**32)
        Faker.seed(seed)
        if entity_type == "PERSON":
            return fake.name()
        elif entity_type == "EMAIL_ADDRESS":
            return fake.email()
        elif entity_type == "PHONE_NUMBER":
            return fake.phone_number()
        return f"[{entity_type}]"

    def pseudonymize(self, text: str, entities: list[dict]) -> str:
        """Replace detected entity spans with consistent pseudonyms."""
        # Sort entities by start offset descending to replace right-to-left
        sorted_entities = sorted(entities, key=lambda e: e["start"], reverse=True)
        result = text
        for entity in sorted_entities:
            original = text[entity["start"]:entity["end"]]
            if original not in self._vault:
                self._vault[original] = self._generate_pseudonym(
                    entity["entity_type"], original
                )
            pseudonym = self._vault[original]
            result = result[:entity["start"]] + pseudonym + result[entity["end"]:]
        return result


# Usage
if __name__ == "__main__":
    ps = SessionPseudonymizer(session_id="session-abc123")
    entities = [
        {"entity_type": "PERSON", "start": 3, "end": 14},
        {"entity_type": "EMAIL_ADDRESS", "start": 23, "end": 46},
    ]
    text = "Hi John Doe, email to john.doe@corp.com for details."
    print(ps.pseudonymize(text, entities))
    # Hi Marcus Webb, email to abby.simmons@example.org for details.
    # (exact output is deterministic given same session_id + original)

